async function seed() {
  try {
    console.log('Seeding 120 database posts...');
    
    // Clear existing posts first to avoid duplicate slug errors
    await sql`TRUNCATE TABLE posts;`;
    
    for (const post of posts) {
      await sql`
        INSERT INTO posts (title, slug, excerpt, content, category, image, date)
        VALUES (${post.title}, ${post.slug}, ${post.excerpt}, ${post.content}, ${post.category}, ${post.image}, ${post.date})
        ON CONFLICT (slug) DO NOTHING;
      `;
    }
    
    console.log('Database successfully seeded with 120 posts!');
  } catch (error) {
    console.error('Seeding database failed:', error);
    process.exit(1);
  }
}

seed();
